
"use client"

import { useState, useEffect } from "react";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Radio, ShieldAlert, Zap, MapPin, AlertTriangle, Info, Bell, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";

const INITIAL_ALERTS = [
  { id: 1, location: "Autostrada Prishtinë - Ferizaj", type: "Radar Mobil", time: "2 minuta më parë", intensity: "Kritike" },
  { id: 2, location: "Rruga B, Prishtinë", type: "Patrullë Policie", time: "15 minuta më parë", intensity: "Mesatare" },
  { id: 3, location: "Magjistralja Pejë - Prishtinë", type: "Kamerë Shpejtësie", time: "Aktiv", intensity: "Lartë" },
  { id: 4, location: "Tranzit, Prizren", type: "Pikë Kontrolli", time: "5 minuta më parë", intensity: "Mesatare" },
];

export default function RadarPage() {
  const [mounted, setMounted] = useState(false);
  const [isScanning, setIsScanning] = useState(true);
  const [alerts, setAlerts] = useState(INITIAL_ALERTS);
  const [isReporting, setIsReporting] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    setMounted(true);
  }, []);

  const handleReportRadar = () => {
    if (!navigator.geolocation) {
      toast({
        variant: "destructive",
        title: "Gabim",
        description: "GPS nuk mbështetet nga pajisja juaj.",
      });
      return;
    }

    setIsReporting(true);

    // Kërkojmë lokacionin me precizitet maksimal për Kosovë
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        
        try {
          // Përdorim OpenStreetMap Nominatim API për saktësi maksimale në Kosovë
          // Shtojmë zoom=18 për të marrë detajet më të imta të rrugës/lagjes
          const response = await fetch(
            `https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${latitude}&lon=${longitude}&zoom=18&addressdetails=1&accept-language=sq`,
            {
              headers: {
                'Accept-Language': 'sq',
                'User-Agent': 'DriveRankKosovo/1.0'
              }
            }
          );
          const data = await response.json();
          
          let locationName = "";
          
          if (data.address) {
            const addr = data.address;
            
            // Prioriteti i emërtimit në Kosovë: Lagja -> Rruga -> Fshati -> Qyteti (Komuna)
            const neighborhood = addr.neighbourhood || addr.suburb || addr.quarter || addr.residential;
            const road = addr.road || addr.street;
            let city = addr.city || addr.town || addr.village || addr.municipality || addr.county;
            
            // Filtri për të zëvendësuar termat e Shqipërisë me ato të Kosovës nëse shfaqen
            if (city && typeof city === 'string') {
              city = city.replace(/Bashkia/g, 'Komuna');
            }

            if (neighborhood && city) {
              locationName = `${neighborhood}, ${city}`;
            } else if (road && city) {
              locationName = `${road}, ${city}`;
            } else if (neighborhood) {
              locationName = neighborhood;
            } else if (city) {
              locationName = city;
            } else {
              locationName = data.display_name.split(',')[0] || "Lokacion në Kosovë";
            }
          }

          // Sigurohemi që emri të jetë i pastër dhe pa terma të huaj
          if (!locationName || locationName === "undefined") {
             locationName = `Zonë e Raportuar (${latitude.toFixed(3)}, ${longitude.toFixed(3)})`;
          }

          const newAlert = {
            id: Date.now(),
            location: locationName,
            type: "Radar LIVE (Raportuar)",
            time: "Sapo tani",
            intensity: "Kritike",
          };

          setAlerts(prev => [newAlert, ...prev]);
          
          toast({
            title: "Raportimi u krye!",
            description: `Lokacioni: ${locationName}`,
          });
        } catch (error) {
          console.error("OSM Geocoding error:", error);
          const fallbackName = `Zonë në Kosovë (${latitude.toFixed(3)})`;
          setAlerts(prev => [{
            id: Date.now(),
            location: fallbackName,
            type: "Radar i Raportuar",
            time: "Sapo tani",
            intensity: "Kritike",
          }, ...prev]);
        } finally {
          setIsReporting(false);
        }
      },
      (error) => {
        setIsReporting(false);
        let errorMsg = "Ju lutem lejoni qasjen 'Exact Location' për saktësi maksimale në Kosovë.";
        if (error.code === error.TIMEOUT) errorMsg = "Koha e kërkimit skadoi. Provoni përsëri jashtë.";
        
        toast({
          variant: "destructive",
          title: "Gabim GPS",
          description: errorMsg,
        });
      },
      { 
        enableHighAccuracy: true, 
        timeout: 15000, 
        maximumAge: 0 
      }
    );
  };

  if (!mounted) return <div className="min-h-screen bg-background" />;

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 relative overflow-hidden safe-bottom">
      <div className="absolute inset-0 z-0 pointer-events-none opacity-20">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] border border-accent rounded-full animate-ping opacity-10" />
      </div>

      <div className="relative z-10 p-6 flex flex-col gap-6">
        <div className="flex items-center justify-between mt-2">
          <div className="flex items-center gap-2">
            <Radio className={cn("w-6 h-6 text-accent", isScanning && "animate-pulse")} />
            <h1 className="text-xl font-black tracking-tighter uppercase italic">RADARËT <span className="text-accent">LIVE</span></h1>
          </div>
          <Badge variant="outline" className="bg-accent/10 border-accent/30 text-accent text-[10px] font-black uppercase">
            KOSOVË • OSM EXACT
          </Badge>
        </div>

        {/* Radar Scanner UI */}
        <div className="relative aspect-square w-full glass rounded-[3rem] border-white/5 flex items-center justify-center overflow-hidden shadow-2xl">
          <div className="absolute inset-0 bg-[conic-gradient(from_0deg,transparent_0deg,rgba(6,182,212,0.2)_360deg)] animate-[spin_4s_linear_infinite]" />
          
          <div className="z-10 text-center space-y-3">
            <div className="bg-background/80 backdrop-blur-xl px-6 py-4 rounded-[2rem] border border-white/10 shadow-lg">
              <p className="text-[10px] font-black text-accent uppercase tracking-[0.2em] mb-1">SKANIMI AKTUAL</p>
              <p className="text-3xl font-black italic">{alerts.length} NJOFTIME</p>
            </div>
            <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest animate-pulse italic">Duke përdorur Inteligjencën Vendor</p>
          </div>

          <div className="absolute bottom-4 text-[8px] font-bold text-muted-foreground uppercase opacity-50">Saktësia: GPS High Precision (Kosova)</div>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-xs font-black text-muted-foreground uppercase tracking-widest">AKTIVITETI I FUNDIT NË KOSOVË</h2>
            <Button variant="ghost" size="sm" className="text-[10px] font-bold text-accent h-6">RIFRESHKO</Button>
          </div>

          <div className="grid gap-3 max-h-[250px] overflow-y-auto no-scrollbar pr-1">
            {alerts.map((alert) => (
              <Card key={alert.id} className={cn(
                "glass border-white/5 p-5 flex items-center gap-4 transition-all rounded-[2rem]",
                alert.intensity === "Kritike" && "border-red-500/30 bg-red-500/5 shadow-lg shadow-red-500/5"
              )}>
                <div className={cn(
                  "w-12 h-12 rounded-2xl flex items-center justify-center shrink-0",
                  alert.intensity === "Kritike" ? "bg-red-500/20 text-red-500" : "bg-accent/10 text-accent"
                )}>
                  {alert.intensity === "Kritike" ? <ShieldAlert className="w-6 h-6" /> : <Info className="w-6 h-6" />}
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="text-sm font-black italic uppercase truncate">{alert.location}</h3>
                  <p className="text-[10px] font-bold text-muted-foreground uppercase mt-1">{alert.type}</p>
                </div>
                <div className="text-right flex flex-col items-end gap-1">
                  <span className="text-[9px] font-bold text-muted-foreground">{alert.time}</span>
                  <Badge className={cn(
                    "text-[8px] font-black py-0 px-2 h-5",
                    alert.intensity === "Kritike" ? "bg-red-500" : "bg-primary"
                  )}>
                    {alert.intensity}
                  </Badge>
                </div>
              </Card>
            ))}
          </div>
        </div>

        <Button 
          onClick={handleReportRadar}
          disabled={isReporting}
          className="w-full h-20 rounded-[2rem] bg-red-500 hover:bg-red-600 text-white font-black italic uppercase text-sm shadow-2xl shadow-red-500/20 active:scale-95 transition-all mt-2"
        >
          {isReporting ? (
            <span className="flex items-center gap-3">
              <Loader2 className="w-6 h-6 animate-spin" />
              DUKE ANALIZUAR LOKACIONIN...
            </span>
          ) : (
            <span className="flex items-center gap-3">
              <AlertTriangle className="w-6 h-6" />
              RAPORTO POLICINË / RADARIN
            </span>
          )}
        </Button>

        <div className="glass rounded-[2rem] p-5 border-white/5 flex items-center gap-4 mb-4">
          <div className="w-12 h-12 rounded-full bg-accent/20 flex items-center justify-center shrink-0">
            <Bell className="text-accent w-6 h-6" />
          </div>
          <p className="text-xs font-bold leading-tight">
            <span className="text-accent">MISIONI:</span> Raportimet tuaja ndihmojnë komunitetin në Kosovë të vozitë më sigurt dhe të shmangë gjobat.
          </p>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
